import '../lib/packet_decoder.dart';
import '../lib/temperature.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final cold = decodeSensorFrame([0x85, 0xff, 0x01]);
  final unavailable = decodeSensorFrame([0x00, 0x80, 0x01]);
  check(cold.rawTemperature == -123, 'decoder signed near-zero value');
  check(unavailable.rawTemperature == -32768, 'decoder sentinel representation');

  check(temperatureCelsius(const SensorFrame(-250, 1)) == -2.5, 'domain negative conversion');
  check(temperatureCelsius(const SensorFrame(-32768, 1)) == null, 'domain sentinel conversion');

  check(temperatureCelsius(cold) == -1.23, 'integrated cold reading');
  check(temperatureCelsius(unavailable) == null, 'integrated unavailable reading');
}
